import { useState, useEffect, useRef, useCallback } from "react";
import { useParams, useSearchParams, useNavigate } from "react-router-dom";
import { Helmet } from "react-helmet-async";
import { trackMovieView, getMovieByImdbId } from "@/lib/api";
import { useContinueWatching } from "@/hooks/useContinueWatching";

interface Server {
  label: string;
  url: (imdbId: string) => string;
}

const SERVERS: Server[] = [
  { label: "Servidor 1", url: (id) => `https://vidsrc.xyz/embed/movie?imdb=${id}` },
  { label: "Servidor 2", url: (id) => `https://vidsrc.to/embed/movie/${id}` },
  { label: "Servidor 3", url: (id) => `https://www.2embed.cc/embed/${id}` },
  { label: "Servidor 4", url: (id) => `https://multiembed.mov/?video_id=${id}&tmdb=1` },
];

const CONTROLS_HIDE_DELAY = 3000; // hide controls after 3s of inactivity in fullscreen

export default function MoviePlayer() {
  const { imdbId } = useParams<{ imdbId: string }>();
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();

  const title = searchParams.get("title") ?? "Reproduciendo";
  const [activeServer, setActiveServer] = useState(0);
  const { saveItem } = useContinueWatching();

  // ── Fullscreen / controls visibility ─────────────────────────────────
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [controlsVisible, setControlsVisible] = useState(true);
  const hideTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Track browser fullscreen changes
  useEffect(() => {
    const handleFSChange = () => {
      const fs = !!document.fullscreenElement;
      setIsFullscreen(fs);
      setControlsVisible(!fs); // show controls immediately when exiting FS
    };
    document.addEventListener("fullscreenchange", handleFSChange);
    return () => document.removeEventListener("fullscreenchange", handleFSChange);
  }, []);

  // Schedule auto-hide of controls in fullscreen
  const scheduleHide = useCallback(() => {
    if (hideTimerRef.current) clearTimeout(hideTimerRef.current);
    if (!isFullscreen) return;
    hideTimerRef.current = setTimeout(() => {
      setControlsVisible(false);
    }, CONTROLS_HIDE_DELAY);
  }, [isFullscreen]);

  // Show controls on mouse move or click, then schedule hide
  const revealControls = useCallback(() => {
    if (!isFullscreen) return;
    setControlsVisible(true);
    scheduleHide();
  }, [isFullscreen, scheduleHide]);

  useEffect(() => {
    if (isFullscreen) {
      scheduleHide();
    }
    return () => {
      if (hideTimerRef.current) clearTimeout(hideTimerRef.current);
    };
  }, [isFullscreen, scheduleHide]);

  // Keyboard: ESC to exit fullscreen
  useEffect(() => {
    const handleKey = (e: KeyboardEvent) => {
      if (e.key === "Escape" && isFullscreen) {
        void document.exitFullscreen();
      }
    };
    document.addEventListener("keydown", handleKey);
    return () => document.removeEventListener("keydown", handleKey);
  }, [isFullscreen]);

  // ── Continue watching ────────────────────────────────────────────────
  useEffect(() => {
    if (imdbId) {
      trackMovieView(imdbId).catch(() => {});

      // Get full movie data to have the poster and internal ID
      getMovieByImdbId(imdbId)
        .then((movie) => {
          saveItem({
            id: movie.id,
            imdbId: imdbId,
            title: movie.title,
            type: "movie",
            poster_url: movie.poster_url,
          });
        })
        .catch(() => {
          // Fallback if API fails, at least save basic info
          saveItem({
            id: imdbId,
            imdbId: imdbId,
            title: title,
            type: "movie",
          });
        });
    }
  }, [imdbId, title]);

