import { useState, useEffect, useRef, useCallback } from "react";
import { useParams, useSearchParams, useNavigate } from "react-router-dom";
import { Helmet } from "react-helmet-async";
import { trackMovieView, getMovieByImdbId } from "@/lib/api";
import { useContinueWatching } from "@/hooks/useContinueWatching";

interface Server {
  label: string;
  url: (imdbId: string) => string;
}

const SERVERS: Server[] = [
  { label: "Servidor 1", url: (id) => `https://vidsrc.xyz/embed/movie?imdb=${id}` },
  { label: "Servidor 2", url: (id) => `https://vidsrc.to/embed/movie/${id}` },
  { label: "Servidor 3", url: (id) => `https://www.2embed.cc/embed/${id}` },
  { label: "Servidor 4", url: (id) => `https://multiembed.mov/?video_id=${id}&tmdb=1` },
];

const CONTROLS_HIDE_DELAY = 3000; // hide controls after 3s of inactivity in fullscreen

export default function MoviePlayer() {
  const { imdbId } = useParams<{ imdbId: string }>();
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();

  const title = searchParams.get("title") ?? "Reproduciendo";
  const [activeServer, setActiveServer] = useState(0);
  const { saveItem } = useContinueWatching();

  // ── Fullscreen / controls visibility ─────────────────────────────────
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [controlsVisible, setControlsVisible] = useState(true);
  const hideTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Track browser fullscreen changes
  useEffect(() => {
    const handleFSChange = () => {
      const fs = !!document.fullscreenElement;
      setIsFullscreen(fs);
      setControlsVisible(!fs); // show controls immediately when exiting FS
    };
    document.addEventListener("fullscreenchange", handleFSChange);
    return () => document.removeEventListener("fullscreenchange", handleFSChange);
  }, []);

  // Schedule auto-hide of controls in fullscreen
  const scheduleHide = useCallback(() => {
    if (hideTimerRef.current) clearTimeout(hideTimerRef.current);
    if (!isFullscreen) return;
    hideTimerRef.current = setTimeout(() => {
      setControlsVisible(false);
    }, CONTROLS_HIDE_DELAY);
  }, [isFullscreen]);

  // Show controls on mouse move or click, then schedule hide
  const revealControls = useCallback(() => {
    if (!isFullscreen) return;
    setControlsVisible(true);
    scheduleHide();
  }, [isFullscreen, scheduleHide]);

  useEffect(() => {
    if (isFullscreen) {
      scheduleHide();
    }
    return () => {
      if (hideTimerRef.current) clearTimeout(hideTimerRef.current);
    };
  }, [isFullscreen, scheduleHide]);

  // Keyboard: ESC to exit fullscreen
  useEffect(() => {
    const handleKey = (e: KeyboardEvent) => {
      if (e.key === "Escape" && isFullscreen) {
        void document.exitFullscreen();
      }
    };
    document.addEventListener("keydown", handleKey);
    return () => document.removeEventListener("keydown", handleKey);
  }, [isFullscreen]);

  // ── Continue watching ────────────────────────────────────────────────
  useEffect(() => {
    if (imdbId) {
      trackMovieView(imdbId).catch(() => {});

      // Get full movie data to have the poster and internal ID
      getMovieByImdbId(imdbId)
        .then((movie) => {
          saveItem({
            id: movie.id,
            imdbId: imdbId,
            title: movie.title,
            type: "movie",
            poster_url: movie.poster_url,
          });
        })
        .catch(() => {
          // Fallback if API fails, at least save basic info
          saveItem({
            id: imdbId,
            imdbId: imdbId,
            title: title,
            type: "movie",
          });
        });
    }
  }, [imdbId, title]);

  const src = SERVERS[activeServer].url(imdbId!);

  return (
    <div
      ref={containerRef}
      className="fixed inset-0 bg-black flex flex-col"
      onMouseMove={revealControls}
      onClick={revealControls}
    >
      <Helmet>
        <title>{title} — Cine Gratín</title>
      </Helmet>

      {/* Transparent overlay when controls are hidden in fullscreen — captures mouse so mousemove works */}
      {isFullscreen && !controlsVisible && (
        <div className="absolute inset-0 z-10" />
      )}

      {/* Controls bar — hidden in fullscreen after inactivity */}
      <div
        className={`flex-shrink-0 bg-black border-b border-white/10 px-3 pt-3 pb-2.5 space-y-2 transition-opacity duration-300 ${
          isFullscreen && !controlsVisible ? "opacity-0 pointer-events-none" : ""
        }`}
      >
        {/* Row 1: back + title */}
        <div className="flex items-center gap-3">
          <button
            onClick={() => navigate(-1)}
            className="flex items-center gap-1.5 text-white/80 hover:text-white transition-colors text-sm font-medium flex-shrink-0"
          >
            <BackIcon /> Volver
          </button>
          <h1 className="text-white/90 font-bold text-sm sm:text-base truncate flex-1 min-w-0">
            {title}
          </h1>
        </div>

        {/* Row 2: servers + utility buttons */}
        <div className="flex items-center gap-1.5 flex-wrap">
          {SERVERS.map((srv, idx) => (
            <button
              key={idx}
              onClick={() => setActiveServer(idx)}
              className={`text-[11px] font-semibold px-2.5 py-1 rounded-md border transition-all ${
                activeServer === idx
                  ? "bg-brand-red border-red-700 text-white shadow-sm"
                  : "bg-white/5 border-white/10 text-white/50 hover:bg-white/10 hover:text-white/80 hover:border-white/20"
              }`}
            >
              {srv.label}
            </button>
          ))}
          <div className="ml-auto flex items-center gap-1.5">
            <button
              onClick={() => document.documentElement.requestFullscreen?.()}
              title="Pantalla completa"
              className="flex items-center gap-1 text-[11px] font-semibold px-2.5 py-1 rounded-md border bg-white/5 border-white/10 text-white/60 hover:bg-white/15 hover:text-white hover:border-white/25 transition-all"
            >
              <FullscreenIcon />
              <span className="hidden sm:inline">Pantalla completa</span>
            </button>
            <button
              onClick={() => window.open(src, "_blank")}
              title="Abrir en nueva pestaña"
              className="flex items-center gap-1 text-[11px] font-semibold px-2.5 py-1 rounded-md border bg-white/5 border-white/10 text-white/60 hover:bg-white/15 hover:text-white hover:border-white/25 transition-all"
            >
              <ExternalLinkIcon />
              <span className="hidden sm:inline">Abrir enlace</span>
            </button>
          </div>
        </div>
      </div>

      {/* Iframe area — fills remaining space, or full viewport in fullscreen */}
      <div className={`relative flex-1 ${isFullscreen ? "absolute inset-0" : ""}`}>
        <iframe
          key={`${src}-${activeServer}`}
          src={src}
          className="absolute inset-0 w-full h-full border-0"
          allowFullScreen
          allow="autoplay; encrypted-media; fullscreen; picture-in-picture"
          referrerPolicy="origin"
          title={title}
        />
      </div>
    </div>
  );
}

function BackIcon() {
  return (
    <svg className="w-4 h-4 flex-shrink-0" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
      <path d="M19 12H5" strokeLinecap="round" strokeLinejoin="round" />
      <path d="M12 19l-7-7 7-7" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
  );
